import{_ as a,c as e,o as r,a4 as t}from"./chunks/framework.nQaBHiNx.js";const b=JSON.parse('{"title":"数据结构 理论基础","description":"","frontmatter":{},"headers":[],"relativePath":"computer/data-structure/basic/index.md","filePath":"computer/data-structure/basic/index.md"}'),o={name:"computer/data-structure/basic/index.md"},i=t('<h1 id="数据结构-理论基础" tabindex="-1">数据结构 理论基础 <a class="header-anchor" href="#数据结构-理论基础" aria-label="Permalink to &quot;数据结构 理论基础&quot;">​</a></h1><h2 id="什么是数据结构" tabindex="-1">什么是数据结构 <a class="header-anchor" href="#什么是数据结构" aria-label="Permalink to &quot;什么是数据结构&quot;">​</a></h2><p>数据结构是计算机中存储、组织数据的方式。</p><p>不同种类的数据结构适合不同种类的应用，部分数据结构甚至是为了解决特定问题而设计出来的。例如 B 树即为加快树状结构访问速度而设计的数据结构，常被应用在数据库和文件系统上。</p><p>在计算机程序设计的过程中，选择适当的数据结构是一项重要工作。许多大型系统的编写经验显示，程序设计的困难程度与最终成果的质量与表现，取决于是否选择了最适合的数据结构。</p><h2 id="什么是算法" tabindex="-1">什么是算法 <a class="header-anchor" href="#什么是算法" aria-label="Permalink to &quot;什么是算法&quot;">​</a></h2><p>解决某个问题的计算方法，步骤称之为算法，在计算机中，指用计算机解决问题的方法。</p><p>在计算机中针对某个问题的算法有很多种，我们对算法的效率从两个方面来考量，分别是</p><ul><li>时间复杂度</li><li>空间复杂度</li></ul><h2 id="时间复杂度" tabindex="-1">时间复杂度 <a class="header-anchor" href="#时间复杂度" aria-label="Permalink to &quot;时间复杂度&quot;">​</a></h2><p>算法的时间复杂度是指算法需要消耗的时间资源。一般来说，计算机算法是问题规模<code>n</code>的函数<code>f(n)</code>，算法的时间复杂度也因此记做<code>T(n)=O(f(n)</code></p><h2 id="空间复杂度" tabindex="-1">空间复杂度 <a class="header-anchor" href="#空间复杂度" aria-label="Permalink to &quot;空间复杂度&quot;">​</a></h2><p>算法的空间复杂度是指算法需要消耗的空间资源。其计算和表示方法与时间复杂度类似，一般都用复杂度的渐近性来表示。同时间复杂度相比，空间复杂度的分析要简单得多。</p><h2 id="取舍" tabindex="-1">取舍 <a class="header-anchor" href="#取舍" aria-label="Permalink to &quot;取舍&quot;">​</a></h2><p>计算机科学中的空间与时间取舍，有时被描述为<code>空间换时间</code>，来优化时间复杂度提升运算速率，或者<code>时间换空间</code>，来优化空间复杂度，减少计算机存储资源的消耗。</p><h2 id="学习资料" tabindex="-1">学习资料 <a class="header-anchor" href="#学习资料" aria-label="Permalink to &quot;学习资料&quot;">​</a></h2><p><a href="https://zh.wikipedia.org/wiki/%E6%95%B0%E6%8D%AE%E7%BB%93%E6%9E%84" target="_blank" rel="noreferrer">维基百科 数据结构</a></p><p><a href="https://zh.wikipedia.org/wiki/%E7%AE%97%E6%B3%95" target="_blank" rel="noreferrer">维基百科 算法</a></p><p><a href="https://book.douban.com/subject/26639401/" target="_blank" rel="noreferrer">豆瓣读书 《学习 JavaScript 数据结构与算法》</a></p><p><a href="https://github.com/felipernb/algorithms.js" target="_blank" rel="noreferrer">Classic algorithms and data structures implemented in JavaScript</a></p>',20),n=[i];function c(d,l,h,s,p,u){return r(),e("div",null,n)}const f=a(o,[["render",c]]);export{b as __pageData,f as default};
